/** PEBS_FRONTEND desc:
  * Register default value:        0x00000800
  * Register full path in IP: BigCore_top/corecr/global/ami_global_msr/PEBS_FRONTEND
  * Processor Event Based Sampling (PEBS) for front-end precise.
  */

#define MSR_PEBS_FRONTEND                (0x000003f7)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 EventId : 4;

                            /* Bits[3:0], Access Type=NA, default=0x00000000*/

                            /*
                               Event to monitor: 1: IFU_MISS 2: MLC_MISS
                               3: ITLB_MISS 4: STLB_MISS 5: DSB_MISS 6: IDQ_READ_BUBBLES
                            */

    UINT32 CriticalFilter : 1;

                            /* Bits[4:4], Access Type=NA, default=0x00000000*/

                            /*
                               When asserted, cycles occurring while IDQ
                               is empty are filtered, otherwise they are
                               monitored.
                            */

    UINT32 Rsvd75 : 3;

                            /* Bits[7:5], Access Type=NA, default=0x00000000*/

                            /* Reserved */

    UINT32 FeLatency : 12;

                            /* Bits[19:8], Access Type=NA, default=0x00000008*/

                            /*
                               Number of consecutive cycles not having less
                               than FE_THRESHOLD bubbles which must occur
                               before logging the event.
                            */

    UINT32 FeThreshold : 4;

                            /* Bits[23:20], Access Type=NA, default=0x00000000*/

                            /*
                               Number of delivery bubbles (or more) of cycles
                               to count.  If number of delivery bubbles is
                               greater than or equal to this field, then
                               count it.
                            */

    UINT32 Rsvd3124 : 8;

                            /* Bits[31:24], Access Type=NA, default=0x00000000*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PEBS_FRONTEND_REGISTER;


/** EPTP desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/corecr/global/ami_global_msr/EPTP
  * Extended Page Table Pointer
  */

#define MSR_EPTP                         (0x00000510)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 Memtype : 3;

                            /* Bits[2:0], Access Type=NA, default=0x00000000*/

                            /* EPT Memory Type */

    UINT32 Rsvd0 : 3;

                            /* Bits[5:3], Access Type=NA, default=0x00000000*/

                            /* Reserved bits */

    UINT32 EptADEnable : 1;

                            /* Bits[6:6], Access Type=NA, default=0x00000000*/

                            /* EPT A/D enable */

    UINT32 EptSssEnable : 1;

                            /* Bits[7:7], Access Type=NA, default=0x00000000*/

                            /*
                               Enable bit for EPT enabling supervisor shadow
                               stack pages
                            */

    UINT32 HlatEnable : 1;

                            /* Bits[8:8], Access Type=NA, default=0x00000000*/

                            /* Enable bit for HLAT */

    UINT32 PlrDisable : 1;

                            /* Bits[9:9], Access Type=NA, default=0x00000000*/

                            /*
                               Disables PLR match in HLAT. If set under HLAT,
                               all memory should be translated through HLAT
                               tables.
                            */

    UINT32 PagingWriteEnable : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /*
                               Enable Paging Write in EPT. This bit gives
                               EPT A/D assists write permissions to an EPT
                               page with no eptW.
                            */

    UINT32 GuestPagingVerification : 1;

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /*
                               Enable Verify Paging Write in EPT. If set
                               all EPT translation of all IA steps should
                               have Paging Write bit set.
                            */

    UINT32 Address0 : 20;

                            /* Bits[31:12], Access Type=NA, default=0x00000000*/

                            /*
                               Page-Map Level-4/5 Address   restrictions
                               : The PMH2_EPTP creg is not a real creg. It
                               is shadow so that a write to the CORE_EPTP
                               will update the ASID_EPTP in the pmh. So if
                               you do a Write then Read of the PMH2_EPTP
                               you will receive Xs.
                            */

    UINT32 Address1 : 20;

                            /* Bits[51:32], Access Type=NA, default=0x00000000*/

                            /*
                               Page-Map Level-4/5 Address   restrictions
                               : The PMH2_EPTP creg is not a real creg. It
                               is shadow so that a write to the CORE_EPTP
                               will update the ASID_EPTP in the pmh. So if
                               you do a Write then Read of the PMH2_EPTP
                               you will receive Xs.
                            */

    UINT32 Rsvd2 : 8;

                            /* Bits[59:52], Access Type=NA, default=0x00000000*/

                            /* Reserved bits */

    UINT32 Seam : 1;

                            /* Bits[60:60], Access Type=NA, default=0x00000000*/

                            /* In SEAM mode bit */

    UINT32 EptMbeEnable : 1;

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               Enable bit for EPT Mode Based Execution (required
                               also paging is ON in guest)
                            */

    UINT32 Ept5l : 1;

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /* Enable 5L EPT */

    UINT32 Enable : 1;

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               EPT enable bit   restrictions : The PMH2_EPTP
                               creg is not a real creg. It is shadow so that
                               a write to the CORE_EPTP will update the ASID_EPTP
                               in the pmh. So if you do a Write then Read
                               of the PMH2_EPTP you will receive Xs.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_EPTP_REGISTER;


