/** FLEX_RATIO desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/FLEX_RATIO
  * This 'flexible boot' register is written by BIOS in order to modify the maximum non-turbo ratio on the next reset.
  */

#define MSR_FLEX_RATIO                   (0x00000194)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 OcExtraVoltage : 8; /**< Over Clocking Extra Voltage */

                            /* Bits[7:0], Access Type=NA, default=0x00000000*/

                            /*
                               Depracated. Extra voltage to be used for Overclocking.The
                               voltage is defined in units of 1/256 Volts.
                            */

    UINT32 FlexRatio : 8; /**< Flex Ratio Override */

                            /* Bits[15:8], Access Type=NA, default=0x00000000*/

                            /*
                               When enabled by the ENABLE bit, the value
                               in this field sets the maximum non-turbo ratio.
                               If this value is greater than the maximum
                               ratio set by hardware, this field is silently
                               ignored. The override value applies on the
                               next reset and not immediately.
                            */

    UINT32 Enable : 1; /**< Flex Enable */

                            /* Bits[16:16], Access Type=NA, default=0x00000000*/

                            /*
                               When set to 1, indicates that the value programmed
                               in FLEX_RATIO field will be used to override
                               the maximum non-turbo ratio on next reboot.
                               When this bit is set to zero, all writes to
                               FLEX_RATIO field are silently ignored.
                            */

    UINT32 OcBins : 3; /**< Overclocking Bins */

                            /* Bits[19:17], Access Type=NA, default=0x00000000*/

                            /*
                               [p]If overclocking is enabled, this field
                               contains how many bins of Core ratio overclocking
                               are supported.[/p] [p]The encoding is:[/p]
                               [list] [*]0:     No Core overclocking is supported
                               [*]1-6:  Max 1-6 bins of Core ratio overclocking
                               is supported. [*]7:     Unlimited [/list]
                               [p]If overclocking is disabled then this field
                               should be ignored.[/p] [p]Overclocking bins
                               imply programming the TURBO_RATIO_LIMIT MSR
                               above its hardware default value.[/p] Overclocking
                               enabled/disabled can be checked in CAPID0_B_0_0_0_PCI.OC_ENABLED.
                            */

    UINT32 OcLock : 1; /**< Overclocking Lock */

                            /* Bits[20:20], Access Type=NA, default=0x00000000*/

                            /*
                               If set, all writes to overclocking limits
                               are disabled. Anyway modifications to overclocking
                               limits prior to setting this lock bit are
                               maintained. This field may only be set by
                               software and it is cleared by hardware only
                               on reset.
                            */

    UINT32 Rsvd21 : 11; /**< Undefined - auto filled rsvd_[31:21] */

                            /* Bits[31:21], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Rsvd32 : 32; /**< Undefined - auto filled rsvd_[63:32] */

                            /* Bits[63:32], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_FLEX_RATIO_REGISTER;


/** PACKAGE_THERM_MARGIN desc:
  * Register default value:        0x00007F00
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/PACKAGE_THERM_MARGIN
  * Temperature margin in PECI temperature counts from the thermal profile specification.  Platform fan control SW is expected to read therm_margin value to control fan or blower speed.
  */

#define MSR_PACKAGE_THERM_MARGIN         (0x000001a1)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 ThermMargin : 16; /**< Thermal Margin */

                            /* Bits[15:0], Access Type=NA, default=0x00007F00*/

                            /*
                               Temperature margin in PECI temperature counts
                               from the thermal profile specification.  THERM_MARGIN
                               is in 2's complement format (8.8 format where
                               MSB equals 1 Sign bit + 7 bits of integer
                               temperature value and the LSB equals 8 precison
                               bits of temperature value).  A value of zero
                               indicates the hottest CPU die temperature
                               is on the thermal profile line. A negative
                               value indicates gap to the thermal profile
                               that platform SW should increase cooling capacity.
                               A sustained negative value should be avoided
                               as it may impact part reliability.
                            */

    UINT32 Rsvd16 : 16; /**< Undefined - auto filled rsvd_[31:16] */

                            /* Bits[31:16], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PACKAGE_THERM_MARGIN_REGISTER;


