/** POWER_CTL desc:
  * Register default value:        0x0020005F
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/POWER_CTL
  * Power Control Register See http://biosbits.org
  */

#define MSR_POWER_CTL                    (0x000001fc)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 EnableBidirProchot : 1;

                            /* Bits[0:0], Access Type=NA, default=0x00000001*/

                            /*
                               Used to enable or disable the response to
                               PROCHOT# input.        When set/enabled, platform
                               can force CPU to throttle to a lower power
                               condition such as Pn/Pm by asserting prochot#.
                               When clear/disabled (default), CPU ignores
                               the status of the prochot input signal.
                            */

    UINT32 C1eEnable : 1;

                            /* Bits[1:1], Access Type=NA, default=0x00000001*/

                            /*
                               When set to '1', will enable the CPU to switch
                               to the Minimum Enhanced Intel SpeedStep Technology
                               operating point when all execution cores enter
                               MWAIT (C1)
                            */

    UINT32 SapmImcC2Policy : 1; /**< System Agent Power Management Memory Controller C2 Policy */

                            /* Bits[2:2], Access Type=NA, default=0x00000001*/

                            /*
                               This bit determines if self-refresh activation
                               is allowed when entering Package C2 State.
                               If it is set to 0b, PCODE will keep the FORCE_SR_OFF
                               bit asserted in Package C2 State and allow
                               its negation according to the defined latency
                               negotiations with the PCH and Display Engine
                               in Package C3 and deeper states.  Otherwise,
                               self-rfresh is allowed in Package C2 State.
                            */

    UINT32 FastBrkSnpEn : 1; /**< Fast Break Snoop Enable */

                            /* Bits[3:3], Access Type=NA, default=0x00000001*/

                            /*
                               This bit controls the VID swing rate for the
                               OTHER_SNP_WAKE events that are detected by
                               the iMPH.  This is the event that is detected
                               by the iMPH when a non-DMI snoopable request
                               is observed while UCLK domain is not functional.
                               0b     Use slow VID swing rate 1b     Use
                               fast VID swing rate
                            */

    UINT32 FastBrkIntEn : 1; /**< Fast Break Interrupt Enable */

                            /* Bits[4:4], Access Type=NA, default=0x00000001*/

                            /* Reserved, not in use */

    UINT32 Rsrvd : 1;

                            /* Bits[5:5], Access Type=NA, default=0x00000000*/

                            /* --- */

    UINT32 PholdCstPreventionInit : 11; /**< PHOLD C-State Prevention Timer Initial Value */

                            /* Bits[16:6], Access Type=NA, default=0x00000001*/

                            /* Reserved, not in use */

    UINT32 PholdSrDisable : 1; /**< PHOLD Self Refresh Disable */

                            /* Bits[17:17], Access Type=NA, default=0x00000000*/

                            /* Reserved, not in use */

    UINT32 PwrPerfPltfrmOvr : 1; /**< Power Performance Platform Override */

                            /* Bits[18:18], Access Type=NA, default=0x00000000*/

                            /* Power Performance Platform Override */

    UINT32 EeTurboDisable : 1; /**< Disable Energy Efficiency Optimization */

                            /* Bits[19:19], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit disables the P-States energy
                               efficiency optimization. Default value is
                               0. Disable/enable the energy efficiency optimization
                               in P-State legacy mode (when PM_ENABLE[HWP_ENABLE]
                               = 0), has an effect only in the turbo range
                               or into PERF_MIN_CTL value if it is not zero
                               set. In HWP mode (PM_ENABLE[HWP_ENABLE]
                               == 1), has an effect between the OS desired
                               or OS maximize to the OS minimize performance
                               setting
                            */

    UINT32 RthDisable : 1; /**< Disable Race to Halt Optimization */

                            /* Bits[20:20], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit disables the Race to Halt
                               optimization and avoids this optimization
                               limitation to execute below the most efficient
                               frequency ratio. Default value is 0 for processors
                               that support Race to Halt optimization
                            */

    UINT32 DisProchotOut : 1;

                            /* Bits[21:21], Access Type=NA, default=0x00000001*/

                            /* Prochot output disable */

    UINT32 ProchotResponse : 1;

                            /* Bits[22:22], Access Type=NA, default=0x00000000*/

                            /* Prochhot Configurable Response Enable */

    UINT32 ProchotLock : 1;

                            /* Bits[23:23], Access Type=NA, default=0x00000000*/

                            /*
                               When set to 1, locks PROCHOT related bits
                               of this MSR. Once set, a reset is required
                               to clear this bit.
                            */

    UINT32 VrThermAlertDisable : 1;

                            /* Bits[24:24], Access Type=NA, default=0x00000000*/

                            /*
                               When set to 1, disables the VR_THERMAL_ALERT
                               signaling.
                            */

    UINT32 DisableRingEe : 1; /**< Disable Ring EE */

                            /* Bits[25:25], Access Type=NA, default=0x00000000*/

                            /* Disable Ring EE */

    UINT32 DisableSaOptimization : 1; /**< Disable SA optimization */

                            /* Bits[26:26], Access Type=NA, default=0x00000000*/

                            /* Disable SA optimization */

    UINT32 DisableOok : 1; /**< Disable OOK */

                            /* Bits[27:27], Access Type=NA, default=0x00000000*/

                            /* Disable OOK */

    UINT32 DisableAutonomous : 1; /**< Disable HWP Autonomous mode */

                            /* Bits[28:28], Access Type=NA, default=0x00000000*/

                            /* Disable HWP Autonomous mode */

    UINT32 Rsvd29 : 1; /**< Undefined - auto filled rsvd_[29:29] */

                            /* Bits[29:29], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 CstatePrewakeDisable : 1; /**< C-state Pre-wake Disable */

                            /* Bits[30:30], Access Type=NA, default=0x00000000*/

                            /* C-state Pre-wake Disable */

    UINT32 ThermRsvdEn : 1;

                            /* Bits[31:31], Access Type=NA, default=0x00000000*/

                            /* Thermal rsvd bit */

    UINT32 PwrPerfTuningDisableSapmCtrl : 1;

                            /* Bits[32:32], Access Type=NA, default=0x00000000*/

                            /*
                               Bit indicates whether power perf tuning algorithm
                               controls SAPM entities
                            */

    UINT32 PwrPerfTuningEnableDynSwitching : 1;

                            /* Bits[33:33], Access Type=NA, default=0x00000000*/

                            /*
                               Bit indicates whether dynamic switching is
                               enabled in power perf tuning algorithm
                            */

    UINT32 PwrPerfTuningCfgMode : 1;

                            /* Bits[34:34], Access Type=NA, default=0x00000000*/

                            /*
                               was PWR_PERF_TUNING_CFG_MODE, change made
                               to match CR_47 definition
                            */

    UINT32 LtrIioDisable : 1;

                            /* Bits[35:35], Access Type=NA, default=0x00000000*/

                            /*
                               Bit indicates whether Pcode should poll the
                               IIO for LTR updates
                            */

    UINT32 PchNegDisable : 1;

                            /* Bits[36:36], Access Type=NA, default=0x00000000*/

                            /*
                               Bit indicates whether latency should be negotiated
                               with PCH for PKGC
                            */

    UINT32 Rsvd37 : 27; /**< Undefined - auto filled rsvd_[63:37] */

                            /* Bits[63:37], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_POWER_CTL_REGISTER;


