/** VR_MISC_CONFIG desc:
  * Register default value:        0x36000000363636
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/VR_MISC_CONFIG
  * Input voltage regulator configuration parameters.
  */

#define MSR_VR_MISC_CONFIG               (0x00000603)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 DynamicLoadLineR : 8; /**< Dynamic Load Line Impedance */

                            /* Bits[7:0], Access Type=NA, default=0x00000036*/

                            /*
                               The Dynamic load line value in 10/256 mOhm
                               increments.   Values range from 0 mOhm to
                               10 mOhm.
                            */

    UINT32 IdleLoadLineR : 8; /**< Idle Load Line Impedance */

                            /* Bits[15:8], Access Type=NA, default=0x00000036*/

                            /*
                               The Idle load line value in 10/256 mOhm increments.
                               Values range from 0 mOhm to 10 mOhm.
                            */

    UINT32 LeakLoadLineR : 8; /**< Static (Leakage) Load Line Impedance */

                            /* Bits[23:16], Access Type=NA, default=0x00000036*/

                            /*
                               The Leakage load line value in 10/256 mOhm
                               increments.   Values range from 0 mOhm to
                               10 mOhm.
                            */

    UINT32 MinVid : 8; /**< Minimum VID */

                            /* Bits[31:24], Access Type=NA, default=0x00000000*/

                            /*
                               Used to constrain the CPU's minimum voltage
                               during package C6/C7 C-states.  The default
                               setting of 0x00 will result in full CPU control
                               over the minimum VID. VID resolution is 10mV
                               / LSB. This is internally clipped by fuses
                               to the C6/C7 voltage.
                            */

    UINT32 IoutOffset : 8; /**< dIout Offset */

                            /* Bits[39:32], Access Type=NA, default=0x00000000*/

                            /*
                               Signed offset added to VR dIout readings for
                               correction. 2s-complement signed         number
                               expressed as a fraction of the IccMax of the
                               VR.  Format: S8.-4.11 (8bits, floating
                               point shifted by 4 points).  Precision: 0.049%
                               (1/2^11) Range: +/-6.25% of IccMax of the
                               VR.         Allowable range may be clipped
                               by processor on a per-SKU basis.
                            */

    UINT32 IoutSlope : 10; /**< dIout Slope Correction */

                            /* Bits[49:40], Access Type=NA, default=0x00000200*/

                            /*
                               This is a slope correction for VR dIout readings
                               for positive/negative correction. This scalar
                               is applied to every dIout reading before it
                               is consumed by the CPU. This scalar represents
                               a 1.x number in U10.1.9 format (0.0 to 2.0
                               scalar in ~0.19% increments)
                            */

    UINT32 IdleExitRampRate : 1; /**< Idle Exit Ramp Rate Control */

                            /* Bits[50:50], Access Type=NA, default=0x00000001*/

                            /*
                               Controls the VR ramp rate on package C-state
                               wake events.  1 == fast, 0 == slow. Note that
                               fast will only apply to the Fast Ramp Voltage
                               in VR_MISC_CONFIG2[7:0]
                            */

    UINT32 IdleEntryRampRate : 1; /**< Idle Entry Ramp Rate Control */

                            /* Bits[51:51], Access Type=NA, default=0x00000000*/

                            /*
                               Controls the VR ramp rate on package C-state
                               entry events.  1 == fast, 0 == slow.  If Decay
                               is set, it has priority. These are used in
                               package C6/C7/C8/C9/C10.
                            */

    UINT32 IdleEntryDecayEnable : 1; /**< Idle Entry Decay Mode Enable */

                            /* Bits[52:52], Access Type=NA, default=0x00000001*/

                            /*
                               Enables decay mode on package C-state entry.
                               Decay mode implies PS2 or deeper.  When Decay
                               is enabled, it has priority over the IDLE_ENTRY_RAMP_RATE.
                               These are used in package C6/C7/C8/C9/C10.
                            */

    UINT32 SlowSlewRateConfig : 2; /**< VR Slow slew rate ratio configuration */

                            /* Bits[54:53], Access Type=NA, default=0x00000001*/

                            /*
                               Defines the desired ratio between the VR fast
                               slope and slow slope.       Pcode programs
                               the VR on BIOS complition       00 - slow
                               = fast/2       01 - slow = fast/4 (default)
                               10 - slow = fast/8       11 - slow = fast/16
                            */

    UINT32 Rsvd55 : 9; /**< Undefined - auto filled rsvd_[63:55] */

                            /* Bits[63:55], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_VR_MISC_CONFIG_REGISTER;


