/** PACKAGE_RAPL_LIMIT desc:
  * Register default value:        0x00148118
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/PACKAGE_RAPL_LIMIT
  * This register allows platform BIOS to limit the power consumption of the processor to the specified values.
  */

#define MSR_PACKAGE_RAPL_LIMIT           (0x00000610)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 PkgPwrLim1 : 15; /**< Package Power Limit 1 */

                            /* Bits[14:0], Access Type=NA, default=0x00000118*/

                            /*
                               Average Power limit value which the package
                               must not exceed over a time window as specified
                               by Power_Limit_1_TIME field above. The processor
                               power consumption will be controlled to the
                               Power_Limit_1 value over an exponential weighted
                               moving average of the time window. This field
                               is specified in the units as identified by
                               the PACKAGE_POWER_SKU_UNIT (MSR 606h). Initial
                               value varies based on the SKU.
                            */

    UINT32 PkgPwrLim1En : 1; /**< Package Power Limit 1 Enable */

                            /* Bits[15:15], Access Type=NA, default=0x00000001*/

                            /*
                               When set, enables processor to apply control
                               policies such that the package average power
                               does not exceed Power_Limit_1 value over an
                               exponential weighted moving average of the
                               time window. This bit is always enabled indicating
                               Power_Limit_1 is always active. Because the
                               processor must maintain the power consumption
                               to the BASE_POWER (a.k.a TDP) value, Power_Limit_1
                               is always enabled.
                            */

    UINT32 PkgClmpLim1 : 1; /**< Package Clamping Limitation 1 */

                            /* Bits[16:16], Access Type=NA, default=0x00000000*/

                            /*
                               When set, allows processor to go below the
                               OS requested P States in order to  maintain
                               the power below Power_Limit_1 value specified
                               below.  This bit is writable only when CPUID.(EAX=06h):EAX[4]
                               is set.
                            */

    UINT32 PkgPwrLim1Time : 7; /**< Package Power Limit 1 Time Window */

                            /* Bits[23:17], Access Type=NA, default=0x0000000A*/

                            /*
                               This indicates the time window  over which
                               Power_Limit_1 value should be maintained.
                               This field is  made up of two numbers from
                               the following equation.  The processor power
                               consumption will be controlled to the  Power_Limit_1
                               value over an exponential weighted moving
                               average  of the time window.  Time Window
                               = (float) ((1+(X/4)) * (2 ^ Y)) Where: X =
                               POWER_LIMIT_1_TIME[23:22] Y = POWER_LIMIT_1_TIME[21:17]
                               The unit of measurement for this field is
                               available from  PACKAGE_POWER_SKU_UNIT (MSR
                               606h). The maximum allowed  value in this
                               field is defined in PACKAGE_POWER_SKU (MSR
                               614h)  PACKAGE_MAX_TIME field.
                            */

    UINT32 Rsvd24 : 8; /**< Undefined - auto filled rsvd_[31:24] */

                            /* Bits[31:24], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 PkgPwrLim2 : 15; /**< Package Power Limit 2 */

                            /* Bits[46:32], Access Type=NA, default=0x00000000*/

                            /*
                               This field indicates the power limitation
                               #2. The unit of measurement is defined in
                               PACKAGE_POWER_SKU_UNIT_MSR[PWR_UNIT].
                            */

    UINT32 PkgPwrLim2En : 1; /**< Package Power Limit 2 Enable */

                            /* Bits[47:47], Access Type=NA, default=0x00000000*/

                            /*
                               This bit enables/disables PKG_PWR_LIM_2. 0b
                               Package Power Limit 2 is Disabled 1b  Package
                               Power Limit 2 is Enabled
                            */

    UINT32 PkgClmpLim2 : 1; /**< Package Clamping Limitation 2 */

                            /* Bits[48:48], Access Type=NA, default=0x00000000*/

                            /*
                               When set, allows processor to go below the
                               OS requested P States in order to  maintain
                               the power below Power_Limit_2 value specified
                               below. This bit is writable only when CPUID.(EAX=6):EAX[4]
                               is set.
                            */

    UINT32 PkgPwrLim2Time : 7; /**< Package Power Limit 2 Time Window */

                            /* Bits[55:49], Access Type=NA, default=0x00000000*/

                            /*
                               This indicates the short duration time window
                               over which Power_Limit_2 value should be maintained.
                               This field is made up of two numbers from
                               the following  equation. The processor power
                               consumption will be controlled to the Power_Limit_2
                               value over an exponential weighted moving
                               average of the time window. Time Window =
                               (float) ((1+(X/4)) * (2 ^ Y)) Where: X = POWER_LIMIT_2_TIME[55:54]
                               Y = POWER_LIMIT_2_TIME[53:49] The unit of
                               measurement for this field is available from
                               PACKAGE_POWER_SKU_UNIT (MSR 606h).
                            */

    UINT32 Rsvd56 : 7; /**< Undefined - auto filled rsvd_[62:56] */

                            /* Bits[62:56], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 PkgPwrLimLock : 1; /**< Package Power Limit Lock */

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               When set, all settings in this register are
                               locked and are treated as Read Only. This
                               bit will typically set by BIOS during boot
                               time or resume from Sx.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PACKAGE_RAPL_LIMIT_REGISTER;


