/** PRIMARY_PLANE_TURBO_POWER_LIMIT desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/PRIMARY_PLANE_TURBO_POWER_LIMIT
  * PP0 RAPL Power Unit Control
  */

#define MSR_PRIMARY_PLANE_TURBO_POWER_LIMIT (0x00000638)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 IaPpPwrLim : 15; /**< IA Cores Power Plane Power Limitation */

                            /* Bits[14:0], Access Type=NA, default=0x00000000*/

                            /*
                               This is the power limitation on the IA cores
                               power plane. The unit of measurement is defined
                               in PACKAGE_POWER_SKU_UNIT_MSR[PWR_UNIT].
                            */

    UINT32 PwrLimCtrlEn : 1; /**< Power Limitation Control Enable */

                            /* Bits[15:15], Access Type=NA, default=0x00000000*/

                            /*
                               This bit must be set in order to limit the
                               power of the IA cores power plane. 0b
                               IA cores power plane power limitation is disabled
                               1b     IA cores power plane power limitation
                               is enabled
                            */

    UINT32 PpClampLim : 1; /**< Power Plane Clamping Limitation */

                            /* Bits[16:16], Access Type=NA, default=0x00000000*/

                            /*
                               Power Plane Clamping limitation - Allow going
                               below P1. 0b     PBM is limited between P1
                               and P0. 1b     PBM can go below P1.
                            */

    UINT32 CtrlTimeWin : 7; /**< Control Time Windows */

                            /* Bits[23:17], Access Type=NA, default=0x00000000*/

                            /*
                               x = CTRL_TIME_WIN[23:22] y = CTRL_TIME_WIN[21:17]
                               The timing interval window is Floating Point
                               number given by 1.x * power(2,y). The unit
                               of measurement is defined in PACKAGE_POWER_SKU_UNIT_MSR[TIME_UNIT].
                               The maximal time window is bounded by PACKAGE_POWER_SKU_MSR[PKG_MAX_WIN].
                               The minimum time window is 1 unit of measurement
                               (as defined above).
                            */

    UINT32 Rsvd24 : 7; /**< Undefined - auto filled rsvd_[30:24] */

                            /* Bits[30:24], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 PpPwrLimLock : 1; /**< Primary Plane Power Limit Lock */

                            /* Bits[31:31], Access Type=NA, default=0x00000000*/

                            /*
                               When set, all settings in this register are
                               locked and are treated as Read Only.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PRIMARY_PLANE_TURBO_POWER_LIMIT_REGISTER;


