/** PKG_SDC_CONFIG_CONTROL desc:
  * Register default value:        0x00000002
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_vcr_msr/PKG_SDC_CONFIG_CONTROL
  * MSR Name: PKG_HDC_CONFIG_CONTROL,   Enables tune  options for the  HDC operation.
  */

#define MSR_PKG_SDC_CONFIG_CONTROL       (0x00000652)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 SdcCxMonitor : 3; /**< SDC_CX_MONITOR */

                            /* Bits[2:0], Access Type=NA, default=0x00000002*/

                            /*
                               HDC_CX_MONITOR, Controls the PKG_HDC_DEEP_RESIDENCY
                               the Cx threshold that >= counts pkg  Cx  residency
                               due forced idle Cx event: 0x0 no-counting,
                               0x1 PC2R only, 0x2 PC3 and deep, 0x3 PC6 and
                               deep, 0x4 PC7 and deep. Default=0x0
                            */

    UINT32 SdcMcntCountMethod : 1; /**< SDC_MCNT_COUNT_METHOD */

                            /* Bits[3:3], Access Type=NA, default=0x00000000*/

                            /*
                               SDC_MCNT_COUNT_METHOD, Controls if MCNT will
                               increment or not  during HDC forced idle time
                               (default=0 meaning 'tick')
                            */

    UINT32 SdcRespectOsMin : 1; /**< SDC_RESPECT_OS_MIN */

                            /* Bits[4:4], Access Type=NA, default=0x00000000*/

                            /*
                               HDC_RESPECT_OS_MIN,HDC Direct control under
                               HWP Minimal, Direct control, is limited by
                               the ratio between most efferent frequency
                               to the OS minimal frequency setting via legacy
                               P state or HWP interfaces. Set this bit will
                               disable this control method
                            */

    UINT32 SdcMaxForceIdleDurationTime : 6; /**< SDC_MAX_FORCE_IDLE_DURATION_TIME */

                            /* Bits[10:5], Access Type=NA, default=0x00000000*/

                            /*
                               HDC_MAX_FORCE_IDLE_DURATION_TIME, Limits the
                               HDC max duration idle time (50usec units).
                               The default value is 0x0, meaning min HDC
                               duty cycles idle time  default value to be
                               set by pcode (e.g. 800usec)
                            */

    UINT32 Spare2 : 1; /**< SPARE2 */

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /* SPARE2. */

    UINT32 SdcDirectControl : 7; /**< SDC_DIRECT_CONTROL */

                            /* Bits[18:12], Access Type=NA, default=0x00000000*/

                            /*
                               HDC_DIRECT_CONTRO, overrides the H/W Heuristics
                               with S/W defined HDC control %. The units
                               are 1/ 127 (0x7F=100%). A value of 0x0 means
                               that HDC is not requested.  HDC due to RAPL
                               power limitation will not be affected by this
                               setting.
                            */

    UINT32 MinActiveTime : 8; /**< MIN_ACTIVE_TIME */

                            /* Bits[26:19], Access Type=NA, default=0x00000000*/

                            /*
                               Limits the forced idle min duration active
                               time (50usec units) starting 100usec as the
                               lowest value. The default value is 0x0, means
                               min HDC duty cycles active time default value
                               to be set by pcode (e.g. 250usec). Default
                               value is 0x0.
                            */

    UINT32 Spare3 : 5; /**< SPARE3 */

                            /* Bits[31:27], Access Type=NA, default=0x00000000*/

                            /* SPARE3. */

    UINT32 Rsvd32 : 32; /**< Undefined - auto filled rsvd_[63:32] */

                            /* Bits[63:32], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PKG_SDC_CONFIG_CONTROL_REGISTER;


