/** MISC_PWR_MGMT desc:
  * Register default value:        0x00000002
  * Register full path in IP: BigCore_top/ucode/uncore_vcrs/ami_virt_msr/MISC_PWR_MGMT
  * Miscellaneous Power Management control. Various model specific features enumeration.
  */

#define MSR_MISC_PWR_MGMT                (0x000001aa)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 SinglePctlEn : 1; /**< Single P-State Control Enable */

                            /* Bits[0:0], Access Type=NA, default=0x00000000*/

                            /*
                               Single_PCTL:  When set (1), will cause PST
                               commands (writes to PERF_CTL) from any
                               cores to set the P-state target (no coordination).
                               This mean that the last thread that writes
                               the P-state request, is the dominant one.
                               If not set this mean that coordination between
                               all the thread requests will be initiated
                               and the resolved result will dominant. Default
                               = 0 (disabled).
                            */

    UINT32 HwpVoting : 1; /**< Enable HWP voting */

                            /* Bits[1:1], Access Type=NA, default=0x00000001*/

                            /*
                               When set (1), The CPU will take into account
                               thread HWP requests for threads that have
                               voting rights only (ignores thread requests
                               if they dont have voting rights).  When reset(0),
                               The CPU will take into account all thread
                               HWP requests, even for threads that don't
                               have voting rights. Setting this bit will
                               cause the HWP Base feature bit to be reported
                               in CPUID as present; clearing will cause it
                               to be reported as non-present. This bit can
                               be set only if PM_ENABLE (HWP_Enable)
                               is clear(0).
                            */

    UINT32 Rsvd2 : 4; /**< Undefined - auto filled rsvd_[05:02] */

                            /* Bits[5:2], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 EnableHwp : 1; /**< Enable HWP */

                            /* Bits[6:6], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit (1) will cause the HWP Base
                               feature bit to report as present (1) in CPUID;
                               clearing this bit will cause CPUID to report
                               the feature as non-present (0). This bit can
                               be set only if PM_ENABLE (HWP_Enable)
                               is clear(0).
                            */

    UINT32 EnableHwpInterrupt : 1; /**< Enable HWP Interrupt (Notification) */

                            /* Bits[7:7], Access Type=NA, default=0x00000000*/

                            /*
                               RW  Setting this bit (1) will cause the HWP
                               CPUID[6].EAX[8]  Notifications feature bit
                               to report as present (1); clearing will report
                               as non-present (0). This bit can be set only
                               if PM_ENABLE (HWP_Enable) is clear(0)
                               and MISC_PWR_MGT[6] is set.
                            */

    UINT32 EnableOutOfBandAutonomous : 1; /**< Enable Autonomous Out of Band */

                            /* Bits[8:8], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit (1) will enable HWP with
                               its default settings but without the ability
                               for software to access HWP MSRs. This bit
                               can be set only if Enumerate HWP bit is clear,
                               MISC_PWR_MGT[6]  (0).
                            */

    UINT32 EnableSdcOob : 1; /**< Enable HDC Out of Band */

                            /* Bits[9:9], Access Type=NA, default=0x00000000*/

                            /*
                               RW  Setting this bit (1) will enable HDC with
                               its default settings but without the ability
                               for software to access PKG_HDC_CTL,
                               PM_CTL1 and THREAD_STALL_COUNTER
                               MSR. This bit can be set only if Enumerate
                               HDC bit is clear (0). Default = 0.
                            */

    UINT32 EnableSdc : 1; /**< Enable HDC */

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /*
                               This bit is reflected in CPUID[6].EAX[13]
                               to represent HDC as present as well the PKG_HDC_CTL,
                               PM_CTL1 and THREAD_STALL_COUNTER
                               MSRs.
                            */

    UINT32 SdcOobCapable : 1; /**< HDC Out of Band Capable */

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /*
                               Read-Only bit in which RDMSR reflects the
                               ENABLE_HDC_OOB capability for BIOS consumption.
                            */

    UINT32 EnableHwpEpp : 1; /**< Enable HWP EPP */

                            /* Bits[12:12], Access Type=NA, default=0x00000000*/

                            /*
                               Enable EPP, RW  Setting this bit (1) will
                               cause the HWP CPUID[6].EAX[10]  Energy Performance
                               Preference bit to report as present (1); clearing
                               will report as non-present (0). This bit can
                               be set only if PM_ENABLE (HWP_Enable)
                               is clear(0) and MISC_PWR_MGT[6] is set.
                            */

    UINT32 Lock : 1; /**< Lock */

                            /* Bits[13:13], Access Type=NA, default=0x00000000*/

                            /*
                               Set this bit will lock this MSR until the
                               next reset
                            */

    UINT32 Rsvd14 : 4; /**< Undefined - auto filled rsvd_[17:14] */

                            /* Bits[17:14], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 PlatPStateCtrl : 1; /**< Platform P-State Control */

                            /* Bits[18:18], Access Type=NA, default=0x00000000*/

                            /* Enables Platform P-State Control */

    UINT32 Rsvd19 : 3; /**< Undefined - auto filled rsvd_[21:19] */

                            /* Bits[21:19], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 LockThermInt : 1; /**< Lock Thermal interrupts */

                            /* Bits[22:22], Access Type=NA, default=0x00000000*/

                            /*
                               Lock_Therm_Int - Ties thermal interrupts from
                               all cores. If set, then a thermal interrupt
                               on one core is routed to all cores.   A value
                               = 0 indicates not active, and a value = 1
                               indicates active.
                            */

    UINT32 Rsvd23 : 9; /**< Undefined - auto filled rsvd_[31:23] */

                            /* Bits[31:23], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Rsvd32 : 32; /**< Undefined - auto filled rsvd_[63:32] */

                            /* Bits[63:32], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_MISC_PWR_MGMT_REGISTER;


