/** PL3_CONTROL desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/core_virt/ami_core_virt_msr/PL3_CONTROL
  * Read/write data from/to pcode through internal mailbox
  */

#define MSR_PL3_CONTROL                  (0x00000615)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 PowerLimit : 15;

                            /* Bits[14:0], Access Type=NA, default=0x00000000*/

                            /*
                               PL3 or PAppMax power level. A power reading
                               above this will be interpreted as a violation
                               (in increments of 1/8th Watt, U12.3)
                            */

    UINT32 Enable : 1;

                            /* Bits[15:15], Access Type=NA, default=0x00000000*/

                            /* 0: PL3 Disabled (default) 1: PL3 Enabled */

    UINT32 ResponseMode : 1;

                            /* Bits[16:16], Access Type=NA, default=0x00000000*/

                            /*
                               0:  Gradual power reduction. 1:  Aggressive
                               power reduction. lnc-a0 adding this bit while
                               pla is frozen hence must add the mask back
                               with pla override. this bit mask removal is
                               handled in urom. need to remove mask override
                               in future steps where pla is not frozen. 1309980413
                            */

    UINT32 Timewindow : 7;

                            /* Bits[23:17], Access Type=NA, default=0x00000000*/

                            /*
                               Duration over which duty cycle control will
                               be maintained. The time is in the tau format
                               (xxYYYYY) in milliseconds
                            */

    UINT32 Dutycyle : 7;

                            /* Bits[30:24], Access Type=NA, default=0x00000000*/

                            /*
                               Expressed in percentage(U7.0%). Clipped to
                               a max value of 100%.
                            */

    UINT32 Lock : 1;

                            /* Bits[31:31], Access Type=NA, default=0x00000000*/

                            /*
                               0=> Updates to fields allowed; 1=> Interface
                               locked. Ignore any writes
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PL3_CONTROL_REGISTER;


