/** HWP_REQUEST desc:
  * Register default value:        0x8000FF01
  * Register full path in IP: BigCore_top/ucode/core_virt/ami_core_virt_msr/HWP_REQUEST
  * Power Management Control Hints to a Logical Processor
  */

#define MSR_HWP_REQUEST             (0x00000774)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 MinimumPerformance : 8; /**< Minimum Performance */

                            /* Bits[7:0], Access Type=NA, default=0x00000001*/

                            /*
                               Conveys a hint to the HWP hardware. The OS
                               programs the minimum performance hint to achieve
                               the required quality of service (QOS) or to
                               meet a service level agreement (SLA) as needed.
                               Note that an excursion below the level specified
                               is possible due to hardware constraints. The
                               default value of this field is HWP_CAPABILITIES.Lowest_Performance.
                            */

    UINT32 MaximumPerformance : 8; /**< Maximum Performance */

                            /* Bits[15:8], Access Type=NA, default=0x000000FF*/

                            /*
                               Conveys a hint to the HWP hardware. The OS
                               programs this field to limit the maximum performance
                               that is expected to be supplied by the HWP
                               hardware. Excursions above the limit requested
                               by OS are possible due to hardware coordination
                               between the processor cores and other components
                               in the package. The default value of this
                               field is HWP_CAPABILITIES.Highest_Performance.
                            */

    UINT32 DesiredPerformance : 8; /**< Desired Performance */

                            /* Bits[23:16], Access Type=NA, default=0x00000000*/

                            /*
                               Conveys a hint to the HWP hardware. When set
                               to zero, hardware autonomous selection determines
                               the performance target. When set to a non-zero
                               value (between the range of Lowest_Performance
                               and Highest_Performance of HWP_CAPABILITIES)
                               conveys an explicit performance request hint
                               to the hardware; effectively disabling HW
                               Autonomous selection. The Desired_Performance
                               input is non-constraining in terms of Performance
                               and Energy Efficiency optimizations, which
                               are independently controlled. The default
                               value of this field is 0.
                            */

    UINT32 EnergyPerformancePreference : 8; /**< Energy performance Preference */

                            /* Bits[31:24], Access Type=NA, default=0x00000080*/

                            /*
                               Conveys a hint to the HWP hardware. The OS
                               may write a range of values from 0 (performance
                               preference) to 0FFH (energy efficiency preference)
                               to influence the rate of performance increase
                               /decrease and the result of the hardware's
                               energy efficiency and performance optimizations.
                               The default value of this field is 80H. Note:
                               If CPUID.06H:EAX[bit 10] indicates that this
                               field is not supported, HWP uses the value
                               of the ENERGY_PERF_BIAS MSR to determine
                               the energy efficiency / performance preference.
                            */

    UINT32 ActivityWindow : 10; /**< Activity window */

                            /* Bits[41:32], Access Type=NA, default=0x00000000*/

                            /*
                               Conveys a hint to the HWP hardware specifying
                               a moving workload history observation window
                               for performance/frequency optimizations. If
                               0, the hardware will determine the appropriate
                               window size. When writing a non-zero value
                               to this field, this field is encoded in the
                               format of bits 38:32 as a 7-bit mantissa and
                               bits 41:39 as a 3-bit exponent value in powers
                               of 10. The resultant value is in microseconds.
                               Thus, the minimal/maximum activity window
                               size is 1 microsecond/1270 seconds. Combined
                               with the Energy_Performance_Preference input,
                               Activity_Window influences the rate of performance
                               increase / decrease. This non-zero hint only
                               has meaning when Desired_Performance = 0.
                               The default value of this field is 0
                            */

    UINT32 PackageControl : 1; /**< Package Control */

                            /* Bits[42:42], Access Type=NA, default=0x00000000*/

                            /*
                               When set causes thread  HWP_REQUEST control
                               inputs to be derived from HWP_REQUEST_PKG
                            */

    UINT32 Rsvd43 : 16; /**< Undefined - auto filled rsvd_[58:43] */

                            /* Bits[58:43], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 ActivityWindowsValid : 1; /**< Activity Windows valid */

                            /* Bits[59:59], Access Type=NA, default=0x00000000*/

                            /*
                               When set 1 means that if the package control
                               bit is set, takes active windows value from
                               this MSR
                            */

    UINT32 EppValid : 1; /**< EPP Valid */

                            /* Bits[60:60], Access Type=NA, default=0x00000000*/

                            /*
                               When set 1 means that if the package control
                               bit is set, takes EPP  value from the this
                               MSR
                            */

    UINT32 DesiredValid : 1; /**< Desired Valid */

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               When set 1 means that if the package control
                               bit is set, takes Desired Performance  value
                               from the this MSR
                            */

    UINT32 MaximumValid : 1; /**< Maximum Valid */

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /*
                               When set 1 means that if the package control
                               bit is set, takes Maximum Performance  value
                               from the this MSR
                            */

    UINT32 MinimumValid : 1; /**< Minimum Valid */

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               When set 1 means that if the package control
                               bit is set, takes Minimum Performance  value
                               from the this MSR
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_HWP_REQUEST_REGISTER;


