/** XU_MACROINSTRUCTION_ALIAS desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/core_virt/ami_core_virt_msr/XU_MACROINSTRUCTION_ALIAS
  * Millicode MSR used to read/write certain fields of the         Macroalias register.         WRMSR will ignore the undefined bits (63:18, 14:13, 10, 6:2).         WRMSR will not signal fault on any combination of bits, it is          softwares responsiblity to make sure that values programmed          this register are consistent and correct         RDMSR will always return 0 in bits 63:18, 14:13, 10:9, 6:2.         RDMSR will return the last value successfully updated by WRMSR
  */

#define MSR_XU_MACROINSTRUCTION_ALIAS    (0x00000903)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 Scale : 2;

                            /* Bits[1:0], Access Type=NA, default=0x00000000*/

                            /*
                               Scale: 00 -> scale 1, 01 -> scale 2, 10 ->
                               scale 4, 11 -> scale 8
                            */

    UINT32 Rsvd2 : 5; /**< Undefined - auto filled rsvd_[06:02] */

                            /* Bits[6:2], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Asize : 3;

                            /* Bits[9:7], Access Type=NA, default=0x00000000*/

                            /*
                               Address size: 000 -> 16-bit, 001 -> 32 bit,
                               010 -> 64-bit, 011-111 -> Reserved
                            */

    UINT32 Rsvd10 : 1; /**< Undefined - auto filled rsvd_[10:10] */

                            /* Bits[10:10], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Osize : 2;

                            /* Bits[12:11], Access Type=NA, default=0x00000000*/

                            /*
                               Operand size: 00 -> DSZ16, 01 -> DSZ32, 10
                               -> DSZ64, 11 -> Reserved
                            */

    UINT32 Rsvd13 : 2; /**< Undefined - auto filled rsvd_[14:13] */

                            /* Bits[14:13], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Lseg : 3;

                            /* Bits[17:15], Access Type=NA, default=0x00000000*/

                            /*
                               Logical Segment: 000-> ES, 001-> CS, 010->
                               SS, 011-> DS, 100-> FS, 101-> GS, 110-111
                               -> Reserved
                            */

    UINT32 Rsvd18 : 14; /**< Undefined - auto filled rsvd_[31:18] */

                            /* Bits[31:18], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Rsvd32 : 32; /**< Undefined - auto filled rsvd_[63:32] */

                            /* Bits[63:32], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_XU_MACROINSTRUCTION_ALIAS_REGISTER;


