                            /* Bits[17:17], Access Type=NA, default=0x00000000*/

                            /* Logic 1 indicates that PCID is enabled */

    UINT32 Osxsave : 1;

                            /* Bits[18:18], Access Type=NA, default=0x00000000*/

                            /* Logic 1 indicates that XSAVE is enabled */

    UINT32 Rsvd19 : 4; /**< Undefined - auto filled rsvd_[22:19] */

                            /* Bits[22:19], Access Type=RO, default=None*/

                            /* Reserved */

