                            /* Bits[23:23], Access Type=NA, default=0x00000000*/

                            /* Logic 1 indicates that VA of 57 width is enabled */

    UINT32 Rsvd24 : 8; /**< Undefined - auto filled rsvd_[31:24] */

                            /* Bits[31:24], Access Type=RO, default=None*/

                            /* Reserved */

