/** CLOCK_CST_CONFIG_CONTROL desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/fscp/ami_fscp_msr/CLOCK_CST_CONFIG_CONTROL
  * C-State Configuration register
  */

#define MSR_CLOCK_CST_CONFIG_CONTROL     (0x000000e2)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 MaxPkgCState : 4;

                            /* Bits[3:0], Access Type=NA, default=0x00000000*/

                            /*
                               Specifies the lowest C-state for the package.
                               This feature does not limit the processor
                               core into specific C-state. The default is
                               set as the factory-configured  package C-state
                               limit.  0000b => C0/C1 (No package C-state
                               support)  0001b => C2  0010b => C3  0011b
                               => C6  0100b => C7  0101b => C7s  0110b =>
                               C8  0111b => C9  1000b => C10
                            */

    UINT32 FusedPkgCStateLimit : 4;

                            /* Bits[7:4], Access Type=NA, default=0x00000000*/

                            /*
                               This value is loaded by pcode from FUSE_PKG_C_STATE
                               into PCU creg, At reset, ucode will cache
                               the value in this reg  0000b => C0/C1 (No
                               package C-state support)  0001b => C2  0010b
                               => C3  0011b => C6  0100b => C7  0101b =>
                               C7s  0110b => C8  0111b => C9  1000b => C10
                            */

    UINT32 Rsvd1 : 2;

                            /* Bits[9:8], Access Type=NA, default=0x00000000*/

                            /* Reserved */

    UINT32 IoMwaitRedirection : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /*
                               When set, will map IO_read instructions sent
                               to IO registers PMG_IO_BASE_ADDRBASE+offset
                               to MWAIT(offset)
                            */

    UINT32 Rsvd2 : 4;

                            /* Bits[14:11], Access Type=NA, default=0x00000000*/

                            /* Reserved */

    UINT32 Lock : 1;

                            /* Bits[15:15], Access Type=NA, default=0x00000000*/

                            /*
                               When set, locks bits 15-0 of this register
                               for further writes, until the next reset occurs.
                            */

    UINT32 Rsvd16 : 1; /**< Undefined - auto filled rsvd_[16:16] */

                            /* Bits[16:16], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Rsvd3 : 8;

                            /* Bits[24:17], Access Type=NA, default=0x00000000*/

                            /* Reserved */

    UINT32 C3StateAutoDemotionEnable : 1;

                            /* Bits[25:25], Access Type=NA, default=0x00000000*/

                            /*
                               When set, processor will conditionally demote
                               C6/C7 requests to C3 based on uncore auto-demote
                               information
                            */

    UINT32 C1StateAutoDemotionEnable : 1;

                            /* Bits[26:26], Access Type=NA, default=0x00000000*/

                            /*
                               When set, processor will conditionally demote
                               C6/C7 requests to C1 based on uncore auto-demote
                               information
                            */

    UINT32 Enc3undemotion : 1;

                            /* Bits[27:27], Access Type=NA, default=0x00000000*/

                            /* Enable Un-Demotion from Demoted C3 */

    UINT32 Enc1undemotion : 1;

                            /* Bits[28:28], Access Type=NA, default=0x00000000*/

                            /* Enable Un-Demotion from Demoted C1 */

    UINT32 Enpkgcautodemotion : 1;

                            /* Bits[29:29], Access Type=NA, default=0x00000000*/

                            /*
                               Enable Package C-State auto-demotion. It enables
                               the use of the history of past package C-State
                               depth and residence as a factor in determining
                               C-State depth
                            */

    UINT32 Enpkgcundemotion : 1;

                            /* Bits[30:30], Access Type=NA, default=0x00000000*/

                            /*
                               Enable Package C-State Un-Demotion. It enables
                               considering cases where demotion was the incorrect
                               decision in determining C-State depth
                            */

    UINT32 TimedMwaitEnable : 1;

                            /* Bits[31:31], Access Type=NA, default=0x00000000*/

                            /* When set, enables Timed MWAIT feature. */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_CLOCK_CST_CONFIG_CONTROL_REGISTER;


