/** SBFT_STATUS desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/fscp/ami_fscp_msr/SBFT_STATUS
  * Returns the result of most recent WRMSR(ACTIVATE_SBFT)
  */

#define MSR_SBFT_STATUS                  (0x000002bd)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 SbftBundleIndex : 14;

                            /* Bits[13:0], Access Type=NA, default=0x00000000*/

                            /* What SBFT program index was run */

    UINT32 ProgramIndex : 2;

                            /* Bits[15:14], Access Type=NA, default=0x00000000*/

                            /*
                               SBFT program index status refers to (Interrupted,
                               Failed)
                            */

    UINT32 NotUsed3116 : 16;

                            /* Bits[31:16], Access Type=NA, default=0x00000000*/

                            /* Not used, will be 0x0 */

    UINT32 ErrorCode : 8;

                            /* Bits[39:32], Access Type=NA, default=0x00000000*/

                            /*
                               SBFT Execution did not start Error codes:
                               [list] [*]0x1: Other thread did not join on
                               time. [*]0x2: Interrupt occurred prior to
                               SBFT start. [*]0x3: Core Power Management
                               sent Abort_SBFT as a response. [*]0x4: There
                               are non-valid chunks in the range to be performed.
                               [*]0x5: Mismatch in arguments between T0/T1.
                               [*]0x6: Core is currently not capable of performing
                               SBFT. [*]0x7: Internal [*]0x8: Exceeded number
                               of Cores allowed to run SBFT concurrently
                               [*]0x9: Interrupt occurred prior to SBFT start.
                               [*]0xA: Reserved [*]Other values are reserved.
                            */

    UINT32 NotUsed6040 : 21;

                            /* Bits[60:40], Access Type=NA, default=0x00000000*/

                            /* Not used, will be 0x0 */

    UINT32 ArchSigChkFailed : 1;

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               Architectural-signature failed, i.e., EBX!=0xACED
                               on last thread to reach HLT
                            */

    UINT32 SbftStatusEncoding : 2;

                            /* Bits[63:62], Access Type=NA, default=0x00000000*/

                            /*
                               Status Encoding.                         00:
                               Failed miserably, e.g., possible transient
                               error.                         01: Failed
                               signature checks                         10:
                               Interrupted                         11: PASS,
                               i.e., all sub-programs requested were executed
                               successfully
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_SBFT_STATUS_REGISTER;


/** FUSA_SCAN_STATUS desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/fscp/ami_fscp_msr/FUSA_SCAN_STATUS
  * Returns the result of most recent WRMSR(ACTIVATE_SCAN)
  */

#define MSR_FUSA_SCAN_STATUS             (0x000002c7)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 ChunkIndexReached : 16;

                            /* Bits[15:0], Access Type=NA, default=0x00000000*/

                            /*
                               Chunk index that was reached in latest scan,
                               can be used as START_CHUNK_INDEX for next
                               WRMSR(ACTIVATE_SCAN)
                            */

    UINT32 StopChunkIndex : 16;

                            /* Bits[31:16], Access Type=NA, default=0x00000000*/

                            /*
                               STOP_CHUNK_INDEX that was provided in latest
                               scan, can be used as STOP_CHUNK_INDEX for
                               next WRMSR(ACTIVATE_SCAN)
                            */

    UINT32 ErrorCode : 8;

                            /* Bits[39:32], Access Type=NA, default=0x00000000*/

                            /*
                               SCAN operation did not start. Error codes:
                               [list] [*]0x1: Other thread did not join on
                               time. [*]0x2: Interrupt occurred prior to
                               SCAN start. [*]0x3: Core Power Management
                               sent Abort_SCAN as a response. [*]0x4: There
                               are non-valid chunks in the range to be performed.
                               [*]0x5: Mismatch in arguments between T0/T1.
                               [*]0x6: Core is currently not capable of performing
                               SCAN. [*]0x7: Internal [*]0x8: Exceeded number
                               of Cores allowed to run SAF concurrently [*]0x9:
                               Interrupt occurred prior to SCAN start. [*]0xA:
                               Reserved [*]Other values are reserved. [/list]
                            */

    UINT32 NotUsed6140 : 22;

                            /* Bits[61:40], Access Type=NA, default=0x00000000*/

                            /* Not used, will be 0x0 */

    UINT32 SscMalfunction : 1;

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /*
                               SSC malfunction, in case the failure is not
                               due to an ECC error.
                            */

    UINT32 ScanErrorObservedInMisr : 1;

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               SCAN error observed in the MISR, in case the
                               failure wasn't due to an ECC error.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_FUSA_SCAN_STATUS_REGISTER;


