/** XRSTOR_INFO desc:
  * Register default value:        0x00000020
  * Register full path in IP: BigCore_top/ucode/fscp/ami_fscp_msr/XRSTOR_INFO
  * Holds XSAVE_AREA  triplet  w/ addition of XCompaction vector for the XMODIFIED optimization.
  */

#define MSR_XRSTOR_INFO                  (0x00000900)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 XsaveAreaCpl : 2;

                            /* Bits[1:0], Access Type=NA, default=0x00000000*/

                            /* The full CPL from the last XRSTOR instruction. */

    UINT32 XsaveAreaVmmHostGuest : 1;

                            /* Bits[2:2], Access Type=NA, default=0x00000000*/

                            /*
                               The VMM Host/Guest state from the last XRSTOR
                               instruction.
                            */

    UINT32 Icecode : 1;

                            /* Bits[3:3], Access Type=NA, default=0x00000000*/

                            /*
                               indicates procedure is called from icecode;
                               purpose is to ensure no xmodified optimization
                               happens. see ARCH PEBS HAS 3.3.4.6
                            */

    UINT32 Rsvd44 : 1;

                            /* Bits[4:4], Access Type=NA, default=0x00000000*/

                            /* Unused bits. */

    UINT32 XsaveAreaValid : 1;

                            /* Bits[5:5], Access Type=NA, default=0x00000001*/

                            /*
                               The XSAVE_AREA valid bit is effectively an
                               address bit of the XSAVE_AREA.  Since all
                               XSAVE_AREAs must be 64 byte aligned, setting
                               this bit forces the misalignment so compare
                               of this XSAVE_AREA and the XSAVE_AREA specified
                               in the XSAVE instruction must miscompare.
                               The miscompare will force all xmodified bits
                               to be treated as modified.
                            */

    UINT32 XsaveAreaAddress0 : 26;

                            /* Bits[31:6], Access Type=NA, default=0x00000000*/

                            /*
                               The XSAVE_AREA linear address from the last
                               XRSTOR.
                            */

    UINT32 XsaveAreaAddress1 : 25;

                            /* Bits[56:32], Access Type=NA, default=0x00000000*/

                            /*
                               The XSAVE_AREA linear address from the last
                               XRSTOR.
                            */

    UINT32 Rsvd6357 : 7;

                            /* Bits[63:57], Access Type=NA, default=0x00000000*/

                            /* Unused bits. */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_XRSTOR_INFO_REGISTER;


