/** DEBUGCTLMSR desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/corecr/global/ami_global_msr/DEBUGCTLMSR
  * Debug MSR for model specific debug features.
  */

#define MSR_DEBUGCTLMSR             (0x000001d9)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 Rsvd0 : 1; /**< Undefined - auto filled rsvd_[00:00] */

                            /* Bits[0:0], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Btf : 1;

                            /* Bits[1:1], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit to 1 enables the processor
                               to treat EFLAGS.TF as single-step on branches
                               instead of single-step on instructions.
                            */

    UINT32 BusLockDetect : 1;

                            /* Bits[2:2], Access Type=NA, default=0x00000000*/

                            /*
                               Indication to set pend #DB for instruction
                               that acquires BUS_LOCK
                            */

    UINT32 Reserved : 3;

                            /* Bits[5:3], Access Type=NA, default=0x00000000*/

                            /* These bits are reserved for future use. */

    UINT32 Tr : 1;

                            /* Bits[6:6], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit to 1 enables branch trace
                               messages to be sent.
                            */

    UINT32 Bts : 1; /**< Branch Trace Store */

                            /* Bits[7:7], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit enables branch trace messages
                               (BTMs) to be logged in a BTS buffer.
                            */

    UINT32 Btint : 1; /**< Branch Trace Interrupt */

                            /* Bits[8:8], Access Type=NA, default=0x00000000*/

                            /*
                               When clear, BTMs are logged in a BTS buffer
                               in circular fashion. When this bit is set,
                               an interrupt is generated by the BTS facility
                               when the BTS buffer is full.
                            */

    UINT32 BtsOffOs : 1;

                            /* Bits[9:9], Access Type=NA, default=0x00000000*/

                            /* When set, BTS or BTM is skipped if CPL = 0. */

    UINT32 BtsOffUsr : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /* When set, BTS or BTM is skipped if CPL > 0. */

    UINT32 FreezeLbrsOnPmi : 1;

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /*
                               When set, the LBR stack is frozen on a PMI
                               request.
                            */

    UINT32 FreezePerfmonCtrsOnPmi : 1;

                            /* Bits[12:12], Access Type=NA, default=0x00000000*/

                            /*
                               When set, each ENABLE bit of the global counter
                               control MSR are frozen (address 38FH) on a
                               PMI request.
                            */

    UINT32 EnablePmiFromUncore : 1;

                            /* Bits[13:13], Access Type=NA, default=0x00000000*/

                            /*
                               When set, enables the logical processor to
                               receive and generate PMI on behalf of the
                               uncore.
                            */

    UINT32 MachineMonitoringOffInSmm : 1;

                            /* Bits[14:14], Access Type=NA, default=0x00000000*/

                            /*
                               When set, freezes perfmon and trace messages
                               while in SMM.
                            */

    UINT32 HlepDebug : 1;

                            /* Bits[15:15], Access Type=NA, default=0x00000000*/

                            /* Enables DR7 debug bit on XBEGIN */

    UINT32 Rsvd16 : 16; /**< Undefined - auto filled rsvd_[31:16] */

                            /* Bits[31:16], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_DEBUGCTLMSR_REGISTER;


/** RTIT_CTL desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/corecr/global/ami_global_msr/RTIT_CTL
  * RTIT Control MSR
  */

#define MSR_RTIT_CTL                (0x00000570)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 TraceEn : 1;

                            /* Bits[0:0], Access Type=NA, default=0x00000000*/

                            /* Enable RTIT Trace on thread */

    UINT32 CycEn : 1;

                            /* Bits[1:1], Access Type=NA, default=0x00000000*/

                            /* Enable Cycle Pkt */

    UINT32 Os : 1;

                            /* Bits[2:2], Access Type=NA, default=0x00000000*/

                            /*
                               When set, only branches in ring 0 (OS mode)
                               will get tracked for RTIT.
                               When both CPL_EQ_0 and CPL_NEQ_0 bits are
                               set, all branches will get tracked for RTIT.
                            */

    UINT32 Usr : 1;

                            /* Bits[3:3], Access Type=NA, default=0x00000000*/

                            /*
                               When set, only branches in non-ring 0 (User
                               mode) will get tracked for RTIT.
                               When both CPL_EQ_0 and CPL_NEQ_0 bits are
                               set, all branches will get tracked for RTIT.
                            */

    UINT32 Rsvd4 : 1; /**< Undefined - auto filled rsvd_[04:04] */

                            /* Bits[4:4], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Fuponptw : 1;

                            /* Bits[5:5], Access Type=NA, default=0x00000000*/

                            /* enable FUP as part of PTWRITE packet */

    UINT32 Rsvd6 : 1; /**< Undefined - auto filled rsvd_[06:06] */

                            /* Bits[6:6], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Cr3FilterEn : 1;

                            /* Bits[7:7], Access Type=NA, default=0x00000000*/

                            /*
                               Enable CR3 filtering, such that tracing is
                               enabled only if CR3 matches the value in RTIT_CR3
                            */

    UINT32 TopaEn : 1;

                            /* Bits[8:8], Access Type=NA, default=0x00000000*/

                            /*
                               When set causes the RTIT output to be in memory
                               via ToPA, else to a single address range
                            */

    UINT32 MtcEn : 1;

                            /* Bits[9:9], Access Type=NA, default=0x00000000*/

                            /* Enable mini time stamp counter */

    UINT32 TscEn : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /*
                               Enable TSC packets, on RTIT enable as well
                               as on bus ratio changes (with CBR).  Implies
                               that CBR is also enabled.
                            */

    UINT32 DisableRetComp : 1;

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /* When set, RETURN compression will be disabled */

    UINT32 PtwEn : 1;

                            /* Bits[12:12], Access Type=NA, default=0x00000000*/

                            /* enable PTWRITE */

    UINT32 BranchEn : 1;

                            /* Bits[13:13], Access Type=NA, default=0x00000000*/

                            /*
                               0: Disable COFI-based packets; 1: Enable COFI-based
                               packets (FUP, TIP, TNT, PIP, CSB);
                            */

    UINT32 MtcFreq : 4;

                            /* Bits[17:14], Access Type=NA, default=0x00000000*/

                            /*
                               Defines MTC Frequency, which is based on the
                               HW Crystal Clock (CTC).   MTC will be sent
                               each time the selected CTC bit toggles.
                               Encodings: 0: CTC[0] 4: CTC[4] 8: CTC[8] 12:
                               CTC[12] 1: CTC[1] 5: CTC[5] 9: CTC[9] 13:
                               CTC[13] 2: CTC[2] 6: CTC[6] 10: CTC[10] 14:
                               CTC[14] 3: CTC[3] 7: CTC[7] 11: CTC[11] 15:
                               CTC[15]
                            */

    UINT32 Rsvd18 : 1; /**< Undefined - auto filled rsvd_[18:18] */

                            /* Bits[18:18], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 CycThresh : 4;

                            /* Bits[22:19], Access Type=NA, default=0x00000000*/

                            /*
                               CYC packet threshold, see 4.53.4 for details.
                               CYC packets will be sent with the first eligible
                               packet after N cycles have passed since the
                               last CYC packet.  If CYC_THRESH is 0 then
                               N=0, otherwise N is defined as 2(CYC_THRESH-1).
                               Encodings: 0: 0 4: 8 8: 128  12: 2048 1: 1
                               5: 16 9: 256  13: 4096 2: 2 6: 32 10: 512
                               14: 8192 3: 4 7: 64 11: 1024 15: 16384
                            */

    UINT32 Rsvd23 : 1; /**< Undefined - auto filled rsvd_[23:23] */

                            /* Bits[23:23], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 PsbFreq : 4;

                            /* Bits[27:24], Access Type=NA, default=0x00000000*/

                            /*
                               Indicates the frequency of PSB packets.
                               PSB packet frequency is based on the number
                               of RTIT packet bytes output, so this field
                               allows the user to determine the increment
                               of RTIT_STATUS. PacketByteCnt that
                               should cause a PSB to be generated.   Note
                               that PSB insertion is not precise, but the
                               average output bytes per PSB should approximate
                               the SW selected period. The average PSB period,
                               in RTIT output bytes, can be expressed as
                               2(PSBFreq+11).   Encodings: 0: 2K 4: 32K 8:
                               512K 12: 8M 1: 4K 5: 64K 9: 1M 13: 16M 2:
                               8K 6: 128K 10: 2M 14: 32M 3: 16K 7: 256K 11:
                               4M 15: 64M
                            */

    UINT32 Rsvd28 : 4; /**< Undefined - auto filled rsvd_[31:28] */

                            /* Bits[31:28], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Addr0Cfg : 4;

                            /* Bits[35:32], Access Type=NA, default=0x00000000*/

                            /*
                               0x0:  No address filtering 0x1:  Enable tracing
                               when IP in [A...B] range 0x2:  Stop tracing
                               when IP in [A...B] range 0x3-0xf:  Reserved
                            */

    UINT32 Addr1Cfg : 4;

                            /* Bits[39:36], Access Type=NA, default=0x00000000*/

                            /*
                               0x0:  No address filtering 0x1:  Enable tracing
                               when IP in [A...B] range 0x2:  Stop tracing
                               when IP in [A...B] range 0x3-0xf:  Reserved
                            */

    UINT32 Rsvd40 : 15; /**< Undefined - auto filled rsvd_[54:40] */

                            /* Bits[54:40], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 DisTnt : 1;

                            /* Bits[55:55], Access Type=NA, default=0x00000000*/

                            /*
                               Disable TNT packet generation. See ticket
                               2207764320 [/IntelRsvd]
                            */

    UINT32 InjectPsbPmiOnEnable : 1;

                            /* Bits[56:56], Access Type=NA, default=0x00000000*/

                            /*
                               Enable preservation of PMI/PSB over xsaves/xrstors.
                               [IntelRsvd]Note: #GP on SNC. May be enabled
                               by patch later. See ticket 1405267396 [/IntelRsvd]
                            */

    UINT32 Rsvd57 : 7; /**< Undefined - auto filled rsvd_[63:57] */

                            /* Bits[63:57], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_RTIT_CTL_REGISTER;


/** U_CET desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/corecr/global/ami_global_msr/U_CET
  * CET user configuration MSR
  */

#define MSR_U_CET                   (0x000006a0)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 ShStkEn : 1;

                            /* Bits[0:0], Access Type=NA, default=0x00000000*/

                            /* Enable shadow stacks */

    UINT32 WrShstkEn : 1;

                            /* Bits[1:1], Access Type=NA, default=0x00000000*/

                            /* Enable WRSS instruction */

    UINT32 EndbrEn : 1;

                            /* Bits[2:2], Access Type=NA, default=0x00000000*/

                            /* Enable indirect call/jmp tracking */

    UINT32 LegiwEn : 1;

                            /* Bits[3:3], Access Type=NA, default=0x00000000*/

                            /*
                               Enable legacy interworking for indirect calls/jumps
                               tracking
                            */

    UINT32 NoTrackEn : 1;

                            /* Bits[4:4], Access Type=NA, default=0x00000000*/

                            /*
                               Enables use of 3E byte as  no-track  prefix
                               for indirect calls and jumps
                            */

    UINT32 SuppressDis : 1;

                            /* Bits[5:5], Access Type=NA, default=0x00000000*/

                            /*
                               disables suppression of CET indirect branch
                               tracking on legacy interwork (each violation
                               requires re-check via bitmap)
                            */

    UINT32 Rsvd : 4;

                            /* Bits[9:6], Access Type=NA, default=0x00000000*/

                            /* reserved */

    UINT32 Suppress : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000000*/

                            /* Suppresses state of ENDBRANCH tracker4 */

    UINT32 Tracker : 1;

                            /* Bits[11:11], Access Type=NA, default=0x00000000*/

                            /*
                               State of ENDBRANCH tracker: 0: idle 1: wait
                               for ENDBRANCH
                            */

    UINT32 EbLegBitmapBase0 : 20;

                            /* Bits[31:12], Access Type=NA, default=0x00000000*/

                            /* Linear address of bitmap of legacy code pages */

    UINT32 EbLegBitmapBase1 : 32;

                            /* Bits[63:32], Access Type=NA, default=0x00000000*/

                            /* Linear address of bitmap of legacy code pages */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_U_CET_REGISTER;


