/** MC1_STATUS desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/corecr/meu/dcu/ami_dcu_msr/MC1_STATUS
  * Machine Check Status Register
  */

#define MSR_MC1_STATUS              (0x00000405)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 Mcacod : 16;

                            /* Bits[15:0], Access Type=NA, default=0x00000000*/

                            /*
                               Machine Check Architecture Error Code: Ld,
                               St, Apic, Eviction, Poison or Snoop Error
                            */

    UINT32 Mscod0 : 16;

                            /* Bits[31:16], Access Type=NA, default=0x00000000*/

                            /* Model Specific Error Code. */

    UINT32 Mscod1 : 6;

                            /* Bits[37:32], Access Type=NA, default=0x00000000*/

                            /* Model Specific Error Code. */

    UINT32 Cecnt : 15;

                            /* Bits[52:38], Access Type=NA, default=0x00000000*/

                            /*
                               This field increments for every correctable
                               error         detected in the DCU even if
                               an uncorrected error is already logged.
                               If the counter overflows the bit 52 of this
                               register will be sticky. This bit will only
                               cleared by         software.
                            */

    UINT32 BitfixAllocated : 1;

                            /* Bits[53:53], Access Type=NA, default=0x00000000*/

                            /*
                               Status tracking is Green if this bit is set
                               when a logged error is allocated into bitfix
                               CAM
                            */

    UINT32 BitfixOvercapacity : 1;

                            /* Bits[54:54], Access Type=NA, default=0x00000000*/

                            /*
                               Status tracking is Yellow if this bit is set
                               when a logged error overflows bitfix CAM (and
                               bitfixing is enabled)
                            */

    UINT32 Ar : 1;

                            /* Bits[55:55], Access Type=NA, default=0x00000000*/

                            /*
                               [p]AR stands for Action Required.  When set
                               it means that error logged requires handling
                               by SW before it can resume execution otherwise
                               it will have to fail if it is not able to
                               handle it.[/p] [p]When cleared, it means that
                               error recovery action is optional for the
                               SW and if it can not handle it there is no
                               need to bring down the system.[/p]
                            */

    UINT32 S : 1;

                            /* Bits[56:56], Access Type=NA, default=0x00000000*/

                            /*
                               When set it means that the error logged was
                               signaled via MCE. Clear means that the error
                               was signaled via CMCI.
                            */

    UINT32 Pcc : 1;

                            /* Bits[57:57], Access Type=NA, default=0x00000000*/

                            /*
                               Processor Context Corrupt indicates if machine
                               state damage has occurred as a result of the
                               error.
                            */

    UINT32 Addrv : 1;

                            /* Bits[58:58], Access Type=NA, default=0x00000000*/

                            /*
                               Indicates if there is an address associated
                               with the reported error.
                            */

    UINT32 Miscv : 1;

                            /* Bits[59:59], Access Type=NA, default=0x00000000*/

                            /*
                               Indicates if the MC1_MISC register contains
                               valid data
                            */

    UINT32 En : 1;

                            /* Bits[60:60], Access Type=NA, default=0x00000000*/

                            /* The enabled error bit. */

    UINT32 Uc : 1;

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               The uncorrected error bit. It indicates that
                               the error is uncorrected when set.
                            */

    UINT32 O : 1;

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /*
                               The overflow bit. It indicates that an error
                               has         occurred while the valid bit is
                               set.
                            */

    UINT32 V : 1;

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               The valid bit. It indicates if the error information
                               in         this register is Valid ('1) or
                               Invalid ('0). This bit is set by         hardware
                               when an error (correctable or uncorrectable)
                               is written         into the register. It is
                               cleared only by software.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_MC1_STATUS_REGISTER;


