#define MSR_MC13_MISC               (0x00000437)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 RecoverableAddressLsb : 6;

                            /* Bits[5:0], Access Type=RW/V, default=0x00000000*/

                            /*
                               The lowest valid recoverable address bit.
                               Indicates the position of the least significant
                               bit (LSB) of the recoverable error address.
                               For example, if the processor logs bits [43:9]
                               of the address, the LSB sub-field in MCi_MISC
                               is 01001b (9 decimal). For this example, bits
                               [8:0] of the recoverable error address in
                               MCi_ADDR should be ignored.
                            */

    UINT32 AddressMode : 3;

                            /* Bits[8:6], Access Type=RW/V, default=0x00000000*/

                            /*
                               Address mode for the address logged in MCi_ADDR.
                               The supported address modes are: MCi_MISC[8:6]
                               Encoding Definition 000
                               Segment Offset 001
                               Linear Address 010
                               Physical Address 011
                               Memory Address 100 to 110
                               Reserved 111
                               Generic
                            */

    UINT32 ModelSpecificInfo0 : 23;

                            /* Bits[31:9], Access Type=RW/V, default=0x00000000*/

                            /* Available when enhanced MCA is in use */

    UINT32 ModelSpecificInfo1 : 32;

                            /* Bits[63:32], Access Type=RW/V, default=0x00000000*/

                            /* Available when enhanced MCA is in use */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_MC13_MISC_REGISTER;

