#define MSR_MC24_STATUS             (0x00000461)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 Mcacod : 16; /**< MCA [machine-check architecture] error code */

                            /* Bits[15:0], Access Type=NA, default=0x00000000*/

                            /*
                               Specifies the machine-check architecture-defined
                               error code for the machine-check error condition
                               detected.
                            */

    UINT32 Mscod : 16; /**< Model Specific Error Code */

                            /* Bits[31:16], Access Type=NA, default=0x00000000*/

                            /*
                               MSCOD: Specifies the model-specific error
                               code that uniquely identifies the machine-check
                               error condition detected. The model-specific
                               error codes may differ among IA-32 processors
                               for the same machine-check error condition.
                               Error codes are listed in the PRM, Chapter
                               16
                            */

    UINT32 OtherInfo : 5; /**< Other Information */

                            /* Bits[36:32], Access Type=NA, default=0x00000000*/

                            /*
                               These bits are implementation-specific and
                               not part of the machine-check architecture
                            */

    UINT32 FwUpdatedErrStatusInd : 1; /**< Firmware updated error status indicator */

                            /* Bits[37:37], Access Type=NA, default=0x00000000*/

                            /*
                               If bit 37 is 0, system firmware has not changed
                               the contents of MCi_STATUS. If bit 37
                               is 1, system firmware may have edited the
                               contents of MCi_STATUS. Available when
                               Enhanced MCA is in use - when MCG_CAP.EMC_P[bit
                               25] is 1 (meaning this bit is architectural
                               and not model specific)
                            */

    UINT32 CorrectedErrorCount : 15; /**< Corrected Error Count */

                            /* Bits[52:38], Access Type=NA, default=0x00000000*/

                            /*
                               CORRECTED_ERROR_COUNT: reports the value of
                               a 15 bit counter that increments each time
                               a corrected error is observed by the MCA recording
                               bank. This count value will continue to increment
                               until cleared by software. The most significant
                               bit, 52, is a sticky count overflow bit. Bitfield
                               is defined as Corrected Error Count only if
                               MCG_CAP.CMCI_P[bit 10] is 1 (meaning
                               this bit is architectural and not model specific)
                            */

    UINT32 ThresholdBasedErrorStatus : 2;

                            /* Bits[54:53], Access Type=NA, default=0x00000001*/

                            /*
                               These bits are used to indicate when the number
                               of corrected errors has exceeded the safe
                               threshold to the point where an uncorrected
                               error has become more likely to happen. Bitfield
                               is defined as Threshold-based error status
                               only if MCG_CAP.TES_P[bit 11] is 1 (meaning
                               this bit is architectural and not model specific)
                               AND if the UC bit in this register is 0 (0
                               meaning the last error was corrected, and
                               1 meaning this is undefined because the status
                               is referring to recoverable health)
                            */

    UINT32 Ar : 1; /**< Recovery Action Required for UCR error */

                            /* Bits[55:55], Access Type=NA, default=0x00000000*/

                            /*
                               AR: Indicates (when set) that MCA error code
                               specific recovery action must be performed
                               by system software at the time this error
                               was signaled.  Bitfield is defined as AR only
                               if MCG_CAP.TES_P [bit 11] is 1 (meaning
                               this bit is architectural and not model specific)
                               AND if MCG_CAP.SER_P[bit 24] is 1 (0
                               meaning this bit is reserved)
                            */

    UINT32 S : 1; /**< Signaling an uncorrected recoverable [UCR] error */

                            /* Bits[56:56], Access Type=NA, default=0x00000000*/

                            /*
                               S: Signals the reporting of UCR errors in
                               this MC bank. Bitfield is defined as S only
                               if MCG_CAP.TES_P[bit 11] is 1 (meaning
                               this bit is architectural and not model specific)
                               AND if MCG_CAP.SER_P[bit 24] is 1 (0
                               meaning this bit is reserved)
                            */

    UINT32 Pcc : 1; /**< Processor context corrupted */

                            /* Bits[57:57], Access Type=NA, default=0x00000000*/

                            /*
                               PCC: Indicates (when set) that the state of
                               the processor might have been corrupted by
                               the error condition detected and that reliable
                               restarting of the processor may not be possible.
                               When clear, this flag indicates that the error
                               did not affect the processor?s state, and
                               software may be able to restart.
                            */

    UINT32 Addrv : 1; /**< MCi_ADDR register valid */

                            /* Bits[58:58], Access Type=NA, default=0x00000000*/

                            /*
                               ADDRV: Indicates (when set) that the MCi_ADDR
                               register contains the address where the error
                               occurred.  When clear, this flag indicates
                               that the MCi_ADDR register does not contain
                               the address where the error occurred.
                            */

    UINT32 Miscv : 1; /**< MCi_MISC register valid */

                            /* Bits[59:59], Access Type=NA, default=0x00000000*/

                            /*
                               MISCV: Indicates (when set) that the MCi_MISC
                               register contains additional information regarding
                               the error.  When clear, this flag indicates
                               that the MCi_MISC register does not contain
                               additional information regarding the error.
                            */

    UINT32 En : 1; /**< Error reporting enabled */

                            /* Bits[60:60], Access Type=NA, default=0x00000000*/

                            /*
                               EN: Indicates (when set) that the error was
                               enabled by the associated EEj bit of the MCi_CTL
                               register.
                            */

    UINT32 Uc : 1; /**< Uncorrected error */

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               UC: Indicates (when set) that the processor
                               did not or was not able to correct the error
                               condition.  When clear, this flag indicates
                               that the processor was able to correct the
                               error condition.
                            */

    UINT32 Ovr : 1; /**< Error Overflow */

                            /* Bits[62:62], Access Type=RW/V, default=0x00000000*/

                            /*
                               OVER: Indicates (when set) that a machine-check
                               error occurred while the results of a previous
                               error were still in the error-reporting register
                               bank (that is, the VAL bit was already set
                               in the MCi_STATUS register). The processor
                               sets the OVER flag and software is responsible
                               for clearing it.
                            */

    UINT32 Val : 1; /**< MCi_STATUS register valid */

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               VAL: Valid flag Indicates (when set) that
                               the information within the Mci_STATUS register
                               is valid. When this flag is set, the processor
                               follows the rules given for the OVER flag
                               in the Mci_STATUS register when overwriting
                               previously valid entries. The processor sets
                               the VAL flag and software is responsible for
                               clearing it.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_MC24_STATUS_REGISTER;

