    UINT32 MiscPackageCtls : 1;

                            /* Bits[10:10], Access Type=NA, default=0x00000001*/

                            /* for Mistletoe mitigation */

    UINT32 EnergyFilteringCtl : 1;

                            /* Bits[11:11], Access Type=NA, default=0x00000001*/

                            /* for Mistletoe mitigation */

    UINT32 DataInvariant : 1;

                            /* Bits[12:12], Access Type=NA, default=0x00000001*/

                            /* If the bit set, DATA_INVARIANT MSR exists */

    UINT32 SbdrSspdNo : 1;

                            /* Bits[13:13], Access Type=NA, default=0x00000001*/

