/** EMON_PERF_GLOBAL_SET desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/core_virt/ami_core_virt_msr/EMON_PERF_GLOBAL_SET
  * The Core PerfMon global overflow set MSR is writable only command register. A read from this register will always return zeros. A write of '1' to any of the bits in this register causes the corresponding bit in the PERF_GLOBAL_STATUS register to set to '1'.
  */

#define MSR_EMON_PERF_GLOBAL_SET    (0x00000391)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 SetOvfGenCtr : 10;

                            /* Bits[9:0], Access Type=NA, default=0x00000000*/

                            /*
                               Range 7:0 relates to General 9-0 respectively.
                               Writes of '1' to any of the bits in this field
                               causes the corresponding bits in the 'Overflow
                               General Counter' field in the PERF_GLOBAL_STATUS
                               register to set to '1'.
                            */

    UINT32 Rsvd10 : 22; /**< Undefined - auto filled rsvd_[31:10] */

                            /* Bits[31:10], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 SetOvfFixedCtr : 4;

                            /* Bits[35:32], Access Type=NA, default=0x00000000*/

                            /*
                               Range 35:32 relates to Fixed Counter 3, 2,
                               1, 0 respectively. Writes of '1' to any of
                               the bits in this field causes the corresponding
                               bits in the 'Overflow Fixed Counter' field
                               of PERF_GLOBAL_STATUS to set to '1'.
                            */

    UINT32 Rsvd36 : 12; /**< Undefined - auto filled rsvd_[47:36] */

                            /* Bits[47:36], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 SetOvfPerfMetricsCtr : 1;

                            /* Bits[48:48], Access Type=NA, default=0x00000000*/

                            /*
                               Write to this bit will set the ovf_status
                               to 1'b1
                            */

    UINT32 Rsvd49 : 6; /**< Undefined - auto filled rsvd_[54:49] */

                            /* Bits[54:49], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 SetRtitTopaPmi : 1;

                            /* Bits[55:55], Access Type=NA, default=0x00000000*/

                            /*
                               RTIT ToPA PMI bit is an indication that a
                               ToPA entry tagged with INTERRUPT was filled
                               up. RTIT continues tracing and no resource/counter
                               will be frozen regardless of DEBUGCTL.Freeze_Perfmon_on_PMI
                               setting. WRMSR of this bit sets the corresponding
                               bit in PERF_GLOBAL_STATUS_RESET.
                            */

    UINT32 Rsvd56 : 2; /**< Undefined - auto filled rsvd_[57:56] */

                            /* Bits[57:56], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 SetLbrsFrozen : 1;

                            /* Bits[58:58], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'clr_lbrs_frozen'
                               bit in the          global status register
                               to set to '1'.
                            */

    UINT32 SetCtrsFrozen : 1;

                            /* Bits[59:59], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'clr_ctrs_frozen'
                               bit in the          global status register
                               to set to '1'.
                            */

    UINT32 SetInterference : 1;

                            /* Bits[60:60], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'clr_interference'
                               bit in the          global status register
                               to set to '1'.
                            */

    UINT32 SetOvfUncore : 1;

                            /* Bits[61:61], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'Overflow
                               Uncore' bit in the global status register
                               to set to '1'.
                            */

    UINT32 SetOvfPebs : 1;

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'Overflow
                               PEBS' bit in the global status register to
                               set to '1'.
                            */

    UINT32 SetCondChanged : 1;

                            /* Bits[63:63], Access Type=NA, default=0x00000000*/

                            /*
                               Writes of '1' to this bit causes the 'Condition
                               Change' bit (bit 63) in the          PERF_GLOBAL_STATUS
                               to set to '1'.
                            */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_EMON_PERF_GLOBAL_SET_REGISTER;


