/** PERMON_EVNTSEL_CNTR0 desc:
  * Register default value:        0x00000000
  * Register full path in IP: BigCore_top/ucode/core_virt/ami_core_virt_msr/PERMON_EVNTSEL_CNTR
  * This is a PerfMon register that is used to control the behavior of an associated performance counter and to select events for that counter.
  */

#define MSR_PERMON_EVNTSEL_CNTR0    (0x00001901)

typedef union {
///
/// Individual bit fields
///
  struct {
    UINT32 EventSelect : 8;

                            /* Bits[7:0], Access Type=NA, default=0x00000000*/

                            /*
                               Selects the event logic unit to detect certain
                               micro-architectural conditions Restrictions:
                               None
                            */

    UINT32 UnitMask : 8;

                            /* Bits[15:8], Access Type=NA, default=0x00000000*/

                            /*
                               Further qualifies the event logic unit selected
                               in the event select field to detect a specific
                               micro-architectural condition. Restrictions:
                               None
                            */

    UINT32 Usr : 1;

                            /* Bits[16:16], Access Type=NA, default=0x00000000*/

                            /*
                               This bit specifies that events are counted
                               only when the processor is operating at current
                               privilege levels 1, 2 or 3 (CPL > 0). This
                               flag can be used in conjunction with the OS
                               flag.
                            */

    UINT32 Os : 1;

                            /* Bits[17:17], Access Type=NA, default=0x00000000*/

                            /*
                               Specifies that events are counted only when
                               the processor is operating at current privilege
                               level 0 (CPL=0). This flag can be used in
                               conjunction with the USR flag.
                               Restrictions: None
                            */

    UINT32 EdgeDetect : 1;

                            /* Bits[18:18], Access Type=NA, default=0x00000000*/

                            /*
                               Enables (when set) edge detection of events.
                               The processor counts the number of deasserted
                               to asserted transitions of any condition that
                               can be expressed by the other fields. The
                               mechanism is limited in that it does not permit
                               back-to-back assertions to be distinguished.
                               [IntelRsvd] Restrictions: ??[/IntelRsvd]
                            */

    UINT32 Rsvd19 : 1; /**< Undefined - auto filled rsvd_[19:19] */

                            /* Bits[19:19], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Pmi : 1;

                            /* Bits[20:20], Access Type=NA, default=0x00000000*/

                            /*
                               APIC interrupt enable. When set, the processor
                               generates an exception through its local APIC
                               on counter overflow for this counter's thread.
                               [IntelRsvd] Restrictions: ??[/IntelRsvd]
                            */

    UINT32 MythrAllthr : 1;

                            /* Bits[21:21], Access Type=NA, default=0x00000000*/

                            /*
                               [list] [*]0: The counter only increments the
                               associated event conditions occurring in the
                               logical processor which programmed the MSR
                               [*]1: Enables counting the associated event
                               conditions occurring across all logical processors
                               sharing a processor core [/list]  Restrictions:
                               None
                            */

    UINT32 EnableBit : 1;

                            /* Bits[22:22], Access Type=NA, default=0x00000000*/

                            /*
                               Enables the corresponding performance counter
                               to commence counting when this bit is set.
                               Restrictions: None
                            */

    UINT32 Invert : 1;

                            /* Bits[23:23], Access Type=NA, default=0x00000000*/

                            /*
                               This bit indicates how the CMASK/Threshold
                               field will be compared to the incoming event:
                               [list] [*] 0: The comparison is: threshold
                               >= event [*] 1: The comparison is inverted
                               from the case where this bit is set to '0':
                               threshold is less than the event. [/list]
                            */

    UINT32 Threshold : 8;

                            /* Bits[31:24], Access Type=NA, default=0x00000000*/

                            /*
                               When CMASK is not zero, the corresponding
                               performance counter increments each cycle
                               if the event count is greater than or equal
                               to the CMASK.
                            */

    UINT32 HleOnly : 1;

                            /* Bits[32:32], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit to '1' restricts the counter
                               to only incrementing for the programmed event
                               during speculative and non-speculative HLE
                               mode. This bit will treated as reserved bit
                               if HLE is fuse disabled.
                            */

    UINT32 HleCheckpointEn : 1;

                            /* Bits[33:33], Access Type=NA, default=0x00000000*/

                            /*
                               Setting this bit to '1' enables the event
                               programmed into the counter to only non-aborted
                               HLE execution i.e. the event count will exclude
                               or not count events that occurred on an aborted
                               HLE path. Only counter 2 supports this capability.
                               This bit will treated as reserved bit if HLE
                               is fuse disabled.
                            */

    UINT32 Rsvd34 : 1; /**< Undefined - auto filled rsvd_[34:34] */

                            /* Bits[34:34], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 EnLbrLog : 1;

                            /* Bits[35:35], Access Type=NA, default=0x00000000*/

                            /*
                               When set, enables updating LBRs with that
                               counter?s event occurrences, if selected event
                               is precise
                            */

    UINT32 ZBit : 1;

                            /* Bits[36:36], Access Type=NA, default=0x00000000*/

                            /*
                               If set, we can count inc == N, or inc between
                               0 to N
                            */

    UINT32 Rsvd37 : 3; /**< Undefined - auto filled rsvd_[39:37] */

                            /* Bits[39:37], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 UnitMask2 : 8;

                            /* Bits[47:40], Access Type=NA, default=0x00000000*/

                            /*
                               Additional 8 sub_events for further qualifies
                               the event logic unit selected in the event
                               select field to detect a specific micro-architectural
                               condition. Restrictions: None
                            */

    UINT32 Rsvd48 : 14; /**< Undefined - auto filled rsvd_[61:48] */

                            /* Bits[61:48], Access Type=RO, default=None*/

                            /* Reserved */

    UINT32 Forceubrkpt : 1;

                            /* Bits[62:62], Access Type=NA, default=0x00000000*/

                            /*
                               When set a MicroBreakPoint occurs each time
                               a none zero Event enters the counter.
                               restrictions : ??
                            */

    UINT32 Rsvd63 : 1; /**< Undefined - auto filled rsvd_[63:63] */

                            /* Bits[63:63], Access Type=RO, default=None*/

                            /* Reserved */

  }     Bits;
  UINT32 Uint32;
  UINT64 Uint64;
} MSR_PERMON_EVNTSEL_CNTR0_REGISTER;

